using System.Collections.ObjectModel;
using BenchmarkDotNet.Attributes;
using TextAnalysis;

namespace TextAnalyzer.Benchmarks;

public class TextAnalyzerBenchmarks
{
    private TextAnalysis.TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // ~500 words of realistic English text with varied word lengths
        var rng = new Random(42);
        string[] vocabulary =
        [
            "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
            "performance", "benchmarking", "infrastructure", "implementation",
            "a", "an", "is", "of", "to", "in", "and", "or", "but", "not",
            "extraordinary", "sophisticated", "algorithm", "optimization",
            "data", "structure", "analysis", "concurrent", "asynchronous",
            "internationalization", "responsiveness", "characterization"
        ];

        var words = new string[500];
        for (int i = 0; i < words.Length; i++)
            words[i] = vocabulary[rng.Next(vocabulary.Length)];

        _analyzer = new TextAnalysis.TextAnalyzer(string.Join(" ", words));
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public ReadOnlyCollection<int> WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

